use std::collections::BinaryHeap;
use std::cmp::Reverse;

#[derive(Eq, PartialEq, Clone, Debug)]
struct Message {
    id: u32,
    urgency: i32,
    content: String,
}
impl Ord for Message {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.urgency.cmp(&other.urgency)
    }
}
impl PartialOrd for Message {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

fn main() {
    let mut message_queue = BinaryHeap::new();

    message_queue.push(Message { id: 1, urgency: 5, content: "Critical Alert".to_string() });
    message_queue.push(Message { id: 2, urgency: 1, content: "Low Priority Update".to_string() });
    message_queue.push(Message { id: 3, urgency: 10, content: "System Failure".to_string() });
    message_queue.push(Message { id: 4, urgency: 5, content: "Medium Event".to_string() });

    println!("Processing messages in order of importance:");
    while let Some(next_message) = message_queue.pop() {
        println!("  Processed Message ID: {}, Urgency: {}", next_message.id, next_message.urgency);
    }
}

