impl PartialOrd for PayloadItem { 
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

fn process_requests() -> BinaryHeap<PayloadItem> {
    let mut heap = BinaryHeap::new();
    let items = vec![
        PayloadItem { priority: 90, data_chunk: "a1b2c3d4".to_string() },
        PayloadItem { priority: 50, data_chunk: "e5f6g7h8".to_string() },
        PayloadItem { priority: 100, data_chunk: "i9j0k1l2".to_string() },
        PayloadItem { priority: 75, data_chunk: "m3n4o5p6".to_string() },
