use std::collections::BinaryHeap;
use std::cmp::{Ordering, Reverse};

struct MoveScore { 
    score: i32,
    depth: usize,
}

impl Eq for MoveScore {}

impl PartialEq for MoveScore {
    fn eq(&self, other: &Self) -> bool {
        self.score == other.score && self.depth == other.depth
    }
}

impl Ord for MoveScore {
    fn cmp(&self, other: &Self) -> Ordering {
        match self.score.cmp(&other.score) {
            Ordering::Equal => self.depth.cmp(&other.depth),
            other => other,
        }
    }
}

impl PartialOrd for MoveScore {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn main() {
    let mut heap = BinaryHeap::new();

    heap.push(MoveScore { score: 10, depth: 5 });
    heap.push(MoveScore { score: 20, depth: 3 });
    heap.push(MoveScore { score: 5, depth: 8 });

    println!("Popped best move (highest score first): ");
    if let Some(best_move) = heap.pop() {
        println!("Score: {}, Depth: {}", best_move.score, best_move.depth);
    }

    println!("Popped next best move: ");
    if let Some(next_move) = heap.pop() {
        println!("Score: {}, Depth: {}", next_move.score, next_move.depth);
    }

    println!("Heap is empty after final pop.");
}

use std::collections::BinaryHeap;

#[derive(Debug, Eq, PartialEq, Clone, Copy)]
struct ScoreEvent {
    priority: i32,
    score_id: u64,
}

impl Ord for ScoreEvent {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.priority.cmp(&other.priority)
            .then_with(|| self.score_id.cmp(&other.score_id))
    }
}

impl PartialOrd for ScoreEvent {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

fn main() {
    let mut event_queue = BinaryHeap::<ScoreEvent>::new();

    event_queue.push(ScoreEvent { priority: 10, score_id: 500 });
    event_queue.push(ScoreEvent { priority: 5, score_id: 200 });
    event_queue.push(ScoreEvent { priority: 10, score_id: 100 });
    event_queue.push(ScoreEvent { priority: 20, score_id: 800 });

    println!("Processing events in order of importance:");
    while let Some(event) = event_queue.pop() {
        println!("Pulled event with priority {} and ID {}", event.priority, event.score_id);
    }
}
